          return <button key={i} onClick={()=>go(opt)} style={{background:bg,border:bd,color:cl,padding:"12px 16px",borderRadius:14,cursor:done?"default":"pointer",fontSize:16,fontWeight:700,transition:"all 0.2s"}}>{opt}</button>;
